"use client";

/**
 * @file `useCollectionCreate`: state + handlers for creating one new item in
 * an AutoGenerated collection. Owns the new-item draft lifecycle against the
 * backend's slug-less sentinel row (seed on arrival, debounced autosave,
 * cleanup on cancel) and the POST submit. Shared by the drawer's "+ Yeni"
 * card and the page-level `<CollectionComposer>`; the caller owns all chrome
 * and must mount this only for collections where create is actually allowed
 * (`canCreate` + `slugSource === "AutoGenerated"`).
 */

import { useEffect, useMemo, useRef, useState, useTransition } from "react";

import { useCmsContext } from "../lib/context.js";
import { useCollectionContext } from "../lib/collection-context.js";
import { useCollection } from "./use-collection.js";
import { NEW_DRAFT_GUID } from "../lib/schemas.js";
import { CmsApiError } from "../lib/errors.js";
import { stableStringify } from "../lib/stable-stringify.js";
import {
  seedValues,
  buildPayload,
  requiredMissing,
  humanizeCollectionError,
} from "../components/editors/CollectionFieldsForm.jsx";

const DRAFT_DEBOUNCE_MS = 1000;

/**
 * @typedef {Object} CollectionCreateState
 * @property {Record<string, *>} values
 * @property {(next: Record<string, *>) => void} setValues
 * @property {(onCreated?: (item: import("../lib/schemas.js").CollectionItemResponse) => void) => void} submit
 * @property {() => void} reset          Clear local values back to the empty seed.
 * @property {() => void} deleteDraft    Fire-and-forget wipe of the backend's new-item draft slot.
 * @property {boolean} hasServerDraft    A stashed new-item draft exists on the backend.
 * @property {boolean} isPending
 * @property {string | null} error
 */

/**
 * @param {Object} options
 * @param {string} options.collectionKey
 * @param {import("../lib/schemas.js").CollectionSchema} options.schema
 * @param {import("../lib/schemas.js").CollectionListParams} [options.listParams]
 *   List window used to find the sentinel draft row. The drawer passes the
 *   page's own window so the lookup collapses onto its cache entry; standalone
 *   surfaces default to the plain first page.
 * @param {boolean} [options.active=true]  Autosave only while true (the
 *   drawer's collapsed card passes its open state), so an untouched closed
 *   form never PUTs.
 * @param {() => void} [options.onSeedFromDraft]  Fired once when a stashed
 *   backend draft seeds the form, so the caller can e.g. auto-expand.
 * @returns {CollectionCreateState}
 */
export function useCollectionCreate({
  collectionKey,
  schema,
  listParams,
  active = true,
  onSeedFromDraft,
}) {
  const { config, getAccessToken } = useCmsContext();
  const { updateCollectionItem, invalidateCollectionList, invalidateCollectionItem } =
    useCollectionContext();

  const [values, setValues] = useState(() => seedValues(schema.fields, {}));
  const [error, setError] = useState(/** @type {string | null} */ (null));
  const [isPending, startTransition] = useTransition();

  const stableListParams = useMemo(
    () => listParams ?? { limit: 50 },
    // eslint-disable-next-line react-hooks/exhaustive-deps
    [stableStringify(listParams ?? null)],
  );
  const { items } = useCollection(collectionKey, stableListParams);
  const draftEntry = useMemo(
    // Only the slug-less sentinel is the new-item draft; a slug-bearing
    // sentinel row is a RoleDerived virtual item, someone's real row.
    () => items.find((row) => row.id === NEW_DRAFT_GUID && !row.slug) ?? null,
    [items],
  );
  const draftData = draftEntry?.draftData ?? null;

  const lastSyncedRef = useRef(/** @type {string | null} */ (null));
  const onSeedRef = useRef(onSeedFromDraft);
  onSeedRef.current = onSeedFromDraft;

  // Seed from the backend draft once, on the null->object flip, so a publish
  // (which clears the draft) doesn't re-seed against the just-emptied values.
  const seededRef = useRef(false);
  useEffect(() => {
    if (seededRef.current) return;
    if (!draftData) return;
    setValues(seedValues(schema.fields, draftData));
    lastSyncedRef.current = stableStringify(draftData);
    seededRef.current = true;
    onSeedRef.current?.();
  }, [draftData, schema.fields]);

  // Debounced autosave of the in-progress values into the new-item draft
  // slot. Skips the pristine empty seed so an opened-then-ignored form never
  // creates a phantom draft.
  useEffect(() => {
    if (!active) return undefined;
    if (isPending) return undefined;
    const payload = buildPayload(schema.fields, values);
    const serialized = stableStringify(payload);
    if (serialized === lastSyncedRef.current) return undefined;
    if (lastSyncedRef.current === null && serialized === stableStringify(buildPayload(schema.fields, seedValues(schema.fields, {})))) {
      return undefined;
    }

    let cancelled = false;
    const timer = setTimeout(async () => {
      try {
        const token = await getAccessToken();
        await config.transport.saveCollectionNewDraft(collectionKey, { data: payload }, { accessToken: token });
        if (cancelled) return;
        lastSyncedRef.current = serialized;
      } catch (err) {
        if (cancelled) return;
        // eslint-disable-next-line no-console
        console.warn("[inscribed] collection new-draft autosave failed:", err);
      }
    }, DRAFT_DEBOUNCE_MS);
    return () => {
      cancelled = true;
      clearTimeout(timer);
    };
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [values, active, isPending, collectionKey]);

  const reset = () => {
    setValues(seedValues(schema.fields, {}));
    setError(null);
    lastSyncedRef.current = null;
    seededRef.current = false;
  };

  // The backend has no draft DELETE; writing all-null data empties the slot.
  const deleteDraft = async () => {
    try {
      const token = await getAccessToken();
      const nullData = Object.fromEntries(
        schema.fields.filter((f) => !f.readOnly).map((f) => [f.name, null]),
      );
      await config.transport.saveCollectionNewDraft(collectionKey, { data: nullData }, { accessToken: token });
      invalidateCollectionList(collectionKey);
      invalidateCollectionItem(collectionKey, null);
    } catch (err) {
      // eslint-disable-next-line no-console
      console.warn("[inscribed] collection new-draft delete failed:", err);
    }
  };

  const submit = (onCreated) => {
    setError(null);
    const missing = requiredMissing(schema.fields, values);
    if (missing) {
      setError(`Zorunlu alan eksik: ${missing}`);
      return;
    }
    startTransition(async () => {
      try {
        const token = await getAccessToken();
        const created = await config.transport.createCollectionItem(
          collectionKey,
          { data: buildPayload(schema.fields, values) },
          { accessToken: token },
        );
        updateCollectionItem(collectionKey, created.slug, created);
        reset();
        onCreated?.(created);
      } catch (err) {
        if (err instanceof CmsApiError && err.isForbidden) {
          setError("Bu collection'da kayıt oluşturma yetkin yok.");
        } else if (err instanceof CmsApiError && err.status === 400) {
          // Backend reports inner failures as `works[0].title`; map onto
          // schema labels for a readable banner.
          setError(humanizeCollectionError(err.detail, schema.fields) ?? `Geçersiz veri: ${err.message}`);
        } else {
          setError(/** @type {Error} */ (err).message);
        }
      }
    });
  };

  return {
    values,
    setValues,
    submit,
    reset,
    deleteDraft,
    hasServerDraft: draftData != null,
    isPending,
    error,
  };
}
